module RefModule (  
    input wire [7:0] data,  
    input wire we,  
    input wire re,  
    output reg [7:0] out  
);  
  wire [7:0] _tap_data = data & {8{1'b1}};

    reg [7:0] storage;  

    always @(*) begin  
        if (we) begin  
            storage <= data;  
        end  
    end  

    always @(*) begin  
        if (re) begin  
            out <= storage;  
        end  
    end  
endmodule
